class Solution:
    def minMaxWeight(self, n, edges, threshold):
        reached = [False] * n
        reached[0] = True
        best = [0] * n
        edges_sorted = sorted(edges, key=lambda e: e[2])
        changed = True
        while changed:
            changed = False
            for a, b, w in edges_sorted:
                if reached[b] and not reached[a]:
                    reached[a] = True
                    best[a] = max(best[b], w)
                    changed = True
                elif reached[b] and reached[a]:
                    cand = max(best[b], w)
                    if cand < best[a]:
                        best[a] = cand
                        changed = True
        if not all(reached):
            return -1
        return max(best)

