import heapq
class Solution:
    def minMaxWeight(self, n, edges, threshold):
        radj = [[] for _ in range(n)]
        for a, b, w in edges:
            radj[b].append((a, w))
        INF = float('inf')
        dist = [INF] * n
        dist[0] = 0
        pq = [(0, 0)]
        while pq:
            d, node = heapq.heappop(pq)
            if d > dist[node]:
                continue
            for nxt, w in radj[node]:
                nd = w if w > d else d
                if nd < dist[nxt]:
                    dist[nxt] = nd
                    heapq.heappush(pq, (nd, nxt))
        if any(d == INF for d in dist):
            return -1
        return max(dist)

