var minMaxWeight = function(n, edges, threshold) {
    const radj = Array.from({length: n}, () => []);
    for (const [a, b, w] of edges) {
        radj[b].push([a, w]);
    }
    const INF = Infinity;
    const dist = new Array(n).fill(INF);
    dist[0] = 0;
    class Heap {
        constructor() { this.a = []; }
        push(x) {
            const a = this.a;
            a.push(x);
            let i = a.length - 1;
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (a[p][0] <= a[i][0]) break;
                [a[p], a[i]] = [a[i], a[p]];
                i = p;
            }
        }
        pop() {
            const a = this.a;
            const top = a[0];
            const last = a.pop();
            if (a.length) {
                a[0] = last;
                let i = 0;
                while (true) {
                    let l = 2 * i + 1, r = 2 * i + 2, s = i;
                    if (l < a.length && a[l][0] < a[s][0]) s = l;
                    if (r < a.length && a[r][0] < a[s][0]) s = r;
                    if (s === i) break;
                    [a[s], a[i]] = [a[i], a[s]];
                    i = s;
                }
            }
            return top;
        }
        get size() { return this.a.length; }
    }
    const pq = new Heap();
    pq.push([0, 0]);
    while (pq.size) {
        const [d, node] = pq.pop();
        if (d > dist[node]) continue;
        for (const [nxt, w] of radj[node]) {
            const nd = w > d ? w : d;
            if (nd < dist[nxt]) {
                dist[nxt] = nd;
                pq.push([nd, nxt]);
            }
        }
    }
    if (dist.some(d => d === INF)) return -1;
    let best = 0;
    for (const d of dist) if (d > best) best = d;
    return best;
};
